const queries = [
  { query: 'Anthropic Claude', topic_tag: 'Claude', priority: 'high' },
  { query: 'AI agents enterprise', topic_tag: 'Agents', priority: 'high' },
  { query: 'AI governance regulation', topic_tag: 'AI Governance', priority: 'high' },
  { query: 'generative AI marketing', topic_tag: 'Marketing AI', priority: 'high' },
  { query: 'Model Context Protocol MCP', topic_tag: 'MCP', priority: 'high' },
  { query: 'AI safety responsible AI', topic_tag: 'AI Safety', priority: 'medium' },
  { query: 'enterprise AI adoption CMO', topic_tag: 'Enterprise AI', priority: 'medium' },
];
return queries.map(q => ({ json: {
  ...q,
  rss_url: 'https://news.google.com/rss/search?q=' + encodeURIComponent('"' + q.query + '"') + '&hl=en-US&gl=US&ceid=US:en'
} }));

// Parse Google News RSS — articles are in <item> blocks. Filter to last 7 days, top 5 per query.
const WINDOW_DAYS = 7;
const cutoff = Date.now() - WINDOW_DAYS * 24 * 60 * 60 * 1000;
const PER_QUERY_LIMIT = 5;
function getTag(tag, block) {
  const re = new RegExp('<' + tag + '(?:\\s[^>]*)?>([\\s\\S]*?)<\\/' + tag + '>', 'i');
  const m = block.match(re);
  if (!m) return '';
  return m[1].replace(/^\s*<!\[CDATA\[/, '').replace(/\]\]>\s*$/, '').trim();
}
const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const it = items[i].json;
  const xml = (typeof it.data === 'string' ? it.data : (typeof it.body === 'string' ? it.body : ''));
  if (!xml) continue;
  const cfg = $('Query Config').itemMatching(i).json;
  const itemRe = /<item(?:\s[^>]*)?>[\s\S]*?<\/item>/gi;
  let m;
  let count = 0;
  while ((m = itemRe.exec(xml)) !== null && count < PER_QUERY_LIMIT) {
    const block = m[0];
    const pub = getTag('pubDate', block);
    if (!pub) continue;
    const t = new Date(pub).getTime();
    if (isNaN(t) || t < cutoff) continue;
    const title = getTag('title', block);
    const link = getTag('link', block);
    const description = getTag('description', block).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    const source = getTag('source', block);
    if (!link || !title) continue;
    // Google News URLs are tracking redirects. Skip those that look like raw GN redirects without resolution.
    out.push({ json: {
      title: title.substring(0, 300),
      url: link,
      description: description.substring(0, 500),
      source_publication: source || 'Unknown',
      published_at: new Date(t).toISOString(),
      query_topic: cfg.topic_tag,
      query: cfg.query,
      priority: cfg.priority,
    }});
    count++;
  }
}
return out;

// Combine Firecrawl scrape output with article metadata.
// Set pairedItem on each output so downstream nodes can trace back to Dedup/Firecrawl inputs.
const out = [];
const fcResults = $input.all();
const metas = $('Dedup: New Articles Only').all();
for (let i = 0; i < fcResults.length; i++) {
  const fc = fcResults[i].json;
  const meta = (metas[i] && metas[i].json) || {};
  if (!fc.success || !fc.data) continue;
  const content = (fc.data.markdown || '').trim();
  if (!content || content.length < 200) continue;
  out.push({
    json: {
      ...meta,
      full_text: content.substring(0, 20000),
      resolved_url: (fc.data.metadata && fc.data.metadata.sourceURL) || meta.url,
      publisher: (fc.data.metadata && fc.data.metadata.siteName) || meta.source_publication,
    },
    pairedItem: { item: i },
  });
}
return out;

// Filter to articles whose URL is not already in Notion. Runs BEFORE Firecrawl to save scrape costs.
const articles = $('Parse + Filter Articles').all().map(it => it.json);
const existing = $input.all();
const existingUrls = new Set();
for (const e of existing) {
  const results = (e.json.results) || [];
  for (const page of results) {
    const ep = (page.properties && page.properties.Episode && page.properties.Episode.rich_text) || [];
    for (const seg of ep) {
      const u = (seg.text && seg.text.link && seg.text.link.url) || '';
      if (u) existingUrls.add(u);
    }
  }
}
return articles.filter(a => !existingUrls.has(a.url)).map(a => ({ json: a }));

